import { NoticeImportant } from '@fs/zion-icon'
import { useStatusOverlay, colors } from '@fs/zion-ui'
import React, { useEffect } from 'react'
import getErrorMessage from '../../lib/getErrorMessage'

function PlaceError({ error, errorType = 'place' }) {
  const showStatusOverlay = useStatusOverlay()
  const errorString = getErrorMessage(error, errorType)

  useEffect(() => {
    if (error && errorString) {
      showStatusOverlay({ message: errorString, type: 'error' })
    }
  }, [error, errorString, showStatusOverlay])

  return (
    !!error && (
      <div style={{ maxWidth: '450px' }}>
        <NoticeImportant color={colors.danger60} size="sm" />
        {errorString}
      </div>
    )
  )
}

const MemoizedPlaceError = React.memo(PlaceError)
export default MemoizedPlaceError
